// src/components/common/Header.jsx
import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import './Header.css';

const Header = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [showDropdown, setShowDropdown] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) {
      try {
        const parsedUser = JSON.parse(userData);
        setUser(parsedUser);
      } catch (error) {
        console.error('Error parsing user data:', error);
      }
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    setUser(null);
    setShowDropdown(false);
    navigate('/');
  };

  const navItems = [
    { path: '/', label: 'Home', mobile: true },
    { path: '/tours', label: 'Tours', mobile: true },
    { path: '/tour-guides', label: 'Tour Guides', mobile: false },
    { path: '/reviews', label: 'Reviews', mobile: false },
    { path: '/contact', label: 'Contact', mobile: false },
  ];

  return (
    <>
      <a href="#main-content" className="skip-to-content">
        Skip to main content
      </a>

      <header className={`header ${scrolled ? 'scrolled' : ''}`}>
        <div className="container">
          <div className="header-content">
            <Link to="/" className="logo">
              <div className="logo-text">
                <h1 className="logo-title">Ceylon Tours</h1>
                <p className="logo-subtitle">Experience the pearl of the Indian Ocean</p>
              </div>
            </Link>

            <nav className="main-nav">
              <ul className="nav-list">
                {navItems.map((item) => (
                  <li key={item.path} className={`nav-item ${!item.mobile ? 'desktop-only' : ''}`}>
                    <Link
                      to={item.path}
                      className={`nav-link ${location.pathname === item.path ? 'active' : ''}`}
                    >
                      {item.label}
                    </Link>
                  </li>
                ))}

                <li className="nav-item">
                  {user ? (
                    <div className="user-menu">
                      <button
                        className="user-avatar-btn"
                        onClick={() => setShowDropdown(!showDropdown)}
                        aria-expanded={showDropdown}
                      >
                        <svg className="account-icon" xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                          <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path>
                          <circle cx="12" cy="7" r="4"></circle>
                        </svg>
                        <span className="user-name">{user.name?.split(' ')[0] || 'User'}</span>
                      </button>

                      {showDropdown && (
                        <div className="dropdown-menu">
                            {/* ... (Keep your existing dropdown-header and items here) ... */}
                            <div className="dropdown-header">
                              <p className="dropdown-name">{user.name}</p>
                            </div>
                            <div className="dropdown-items">
                                <Link to="/account" className="dropdown-item" onClick={() => setShowDropdown(false)}>My Account</Link>
                                <button className="dropdown-item logout-btn" onClick={handleLogout}>Logout</button>
                            </div>
                        </div>
                      )}
                    </div>
                  ) : (
                    <Link to="/login" className="nav-link login-button-fixed">
                      <svg className="login-icon" xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"></path>
                        <polyline points="10 17 15 12 10 7"></polyline>
                        <line x1="15" y1="12" x2="3" y2="12"></line>
                      </svg>
                      <span className="login-text">Login</span>
                    </Link>
                  )}
                </li>
              </ul>
            </nav>
          </div>
        </div>
        {/* Fixed Overlay: Rendered outside the button to prevent click-blocking */}
        {showDropdown && (
          <div className="dropdown-clickable-overlay" onClick={() => setShowDropdown(false)} />
        )}
      </header>
    </>
  );
};

export default Header;
